 1	import type { FC } from 'react';
 2	import { DetailsItem } from 'src/components/DetailItems/DetailItem';
 3	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 4	import { isPlanEditable } from 'src/plans/details/components/PlanStatus/utils/utils';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { Label, Stack, StackItem } from '@patternfly/react-core';
 8	
 9	import type { EditableDetailsItemProps } from '../../../utils/types';
10	
11	import { getSkipGuestConversion, getUseCompatibilityMode } from './utils/utils';
12	import GuestConversionEditModal from './GuestConversionEditModal';
13	
14	const GuestConversionDetailsItem: FC<EditableDetailsItemProps> = ({
15	  canPatch,
16	  plan,
17	  shouldRender,
18	}) => {
19	  const { t } = useForkliftTranslation();
20	  const { showModal } = useModal();
21	
22	  if (!shouldRender) return null;
23	
24	  const skipGuestConversion = getSkipGuestConversion(plan);
25	  const useCompatibilityMode = getUseCompatibilityMode(plan) ?? true;
26	
27	  return (
28	    <DetailsItem
29	      testId="guest-conversion-mode-detail-item"
30	      title={t('Guest conversion mode')}
31	      content={
32	        <Stack>
33	          <StackItem>
34	            <Label isCompact>
35	              {skipGuestConversion ? t('Skip guest conversion') : t('Include guest conversion')}
36	            </Label>
37	          </StackItem>
38	
39	          {skipGuestConversion && (
40	            <StackItem>
41	              <Label isCompact>
42	                {useCompatibilityMode
43	                  ? t('Compatibility mode enabled')
44	                  : t('Compatibility mode disabled')}
45	              </Label>
46	            </StackItem>
47	          )}
48	        </Stack>
49	      }
50	      crumbs={['spec', 'skipGuestConversion']}
51	      onEdit={() => {
52	        showModal(<GuestConversionEditModal resource={plan} />);
53	      }}
54	      canEdit={canPatch && isPlanEditable(plan)}
55	    />
56	  );
57	};
58	
59	export default GuestConversionDetailsItem;

